import React, { useEffect, useState, useMemo } from 'react';
import fileService from '../services/fileService';
import { useNavigate, Link } from 'react-router-dom';
import authService from '../services/authService';
import adminService from '../services/adminService';

function Dashboard(){
  const [file, setFile] = useState(null);
  const [files, setFiles] = useState([]);
  const [passkey, setPasskey] = useState('');
  const [user, setUser] = useState({ name: '' });
  const navigate = useNavigate();

  const fetch = async()=>{ try{ const res = await fileService.getMyFiles(); setFiles(res || []); }catch(e){ console.error(e); } };
  useEffect(()=>{ fetch(); },[]);

  useEffect(() => {
    (async () => {
      try {
        const res = await authService.getProfile();
        setUser(res);
      } catch (e) {
        const name = localStorage.getItem('userName') || localStorage.getItem('userEmail') || '';
        setUser({ name });
      }
    })();
  }, []);

  const upload = async(e)=>{ 
    e.preventDefault(); 
    if(!file) return alert('Select file'); 
    if(!passkey) return alert('Enter passkey'); 
    try{
      const t0 = performance.now();
      const res = await fileService.uploadFile(file, passkey);
      const clientMs = performance.now() - t0;

      // send client-side metric to admin API (non-blocking)
      (async ()=>{
        try{
          const token = localStorage.getItem('token');
          if(token && res?.fileId){
            await adminService.sendClientMetric(res.fileId, clientMs, { filename: file.name, size: file.size }, token);
          }
        }catch(me){ console.warn('Could not send client metric',me); }
      })();

      alert('Uploaded'); 
      setPasskey(''); setFile(null); (e.target.reset && e.target.reset()); fetch(); 
    }catch(e){ 
      alert(e?.response?.data?.error || 'Upload failed'); 
    } 
  };

  const totalFiles = files.length;
  const totalSize = useMemo(()=>{
    try{ return files.reduce((s,f)=>s + (f.size||0), 0); }catch{return 0}
  },[files]);

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-purple-100 p-8">
      <div className="w-full max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Left column - Welcome & stats */}
        <div className="lg:col-span-1 bg-white rounded-2xl shadow p-6 flex flex-col gap-6">
          <div className="flex items-center justify-between">
            <div>
              <div className="text-xl font-semibold text-blue-700">Welcome back,</div>
              <div className="text-2xl font-bold">{user.name || 'User'}</div>
            </div>
            <Link to="/profile" title="Profile">
              <div className="inline-flex items-center justify-center bg-blue-100 rounded-full w-12 h-12 text-xl font-bold text-blue-600 shadow">
                <span role="img" aria-label="profile">👤</span>
              </div>
            </Link>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="p-4 bg-gradient-to-br from-white to-blue-50 rounded-lg border">
              <div className="text-sm text-gray-500">Files</div>
              <div className="text-2xl font-bold">{totalFiles}</div>
            </div>
            <div className="p-4 bg-gradient-to-br from-white to-blue-50 rounded-lg border">
              <div className="text-sm text-gray-500">Storage</div>
              <div className="text-2xl font-bold">{(totalSize/1024/1024).toFixed(2)} MB</div>
            </div>
          </div>

          <div>
            <h4 className="text-sm font-semibold text-gray-700 mb-2">Quick Actions</h4>
            <div className="flex flex-col gap-2">
              <button onClick={()=>document.getElementById('file-input')?.click()} className="w-full text-left bg-blue-600 text-white px-4 py-2 rounded-lg">Upload File</button>
              <button onClick={()=>navigate('/grant-access')} className="w-full text-left bg-green-500 text-white px-4 py-2 rounded-lg">Manage Access</button>
              {/* Activity logs removed from user dashboard */}
            </div>
          </div>
        </div>

        {/* Middle column - Upload card (prominent) */}
        <div className="lg:col-span-2 bg-white rounded-2xl shadow p-6">
          <div className="flex items-center justify-between mb-4">
            <div>
              <h2 className="text-2xl font-bold text-blue-700">Your Documents</h2>
              <p className="text-gray-500">Encrypted, watermarked and access-controlled — managed from one place.</p>
            </div>
            <div className="text-sm text-gray-500">Last sync: {new Date().toLocaleString()}</div>
          </div>

          <form onSubmit={upload} className="flex flex-col md:flex-row gap-4 items-center mb-6">
            <label className="flex-1 p-4 border-2 border-dashed rounded-lg bg-gray-50 hover:bg-gray-100 cursor-pointer text-center">
              <input id="file-input" type="file" onChange={e=>setFile(e.target.files[0])} className="hidden" />
              <div className="text-gray-600">Drag & drop a file here, or click to select</div>
              {file && <div className="mt-2 text-sm text-gray-700">Selected: {file.name} — {(file.size/1024/1024).toFixed(2)} MB</div>}
            </label>
            <input type="password" placeholder="Encryption passkey" value={passkey} onChange={e=>setPasskey(e.target.value)} className="border p-3 rounded w-full md:w-56" />
            <button className="bg-gradient-to-r from-blue-600 to-purple-600 text-white px-6 py-3 rounded-lg shadow hover:from-blue-700">Upload Securely</button>
          </form>

          <div>
            <h3 className="text-lg font-semibold mb-3 text-gray-700">Recent Files</h3>
            {files.length === 0 ? (
              <div className="p-6 text-center text-gray-500">No files yet — upload your first secure document.</div>
            ) : (
              <div className="grid md:grid-cols-2 gap-4">
                {files.slice(0,6).map(f => (
                  <div key={f.id} className="p-4 border rounded-lg flex items-center justify-between hover:shadow">
                    <div>
                      <div className="text-sm text-gray-500">{f.originalname}</div>
                      <div className="text-xs text-gray-400">Uploaded: {new Date(f.uploaded_at).toLocaleString()}</div>
                    </div>
                    <div className="flex gap-2">
                      <button onClick={() => navigate('/view/' + f.id)} className="bg-blue-500 text-white px-3 py-1 rounded">View</button>
                      <button onClick={() => navigate('/grant-access/' + f.id)} className="bg-green-500 text-white px-3 py-1 rounded">Grant</button>
                      <button onClick={async () => { if(window.confirm('Delete this file?')){ await fileService.deleteFile(f.id); fetch(); } }} className="bg-red-500 text-white px-3 py-1 rounded">Delete</button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

export default Dashboard;
